from datasets import load_from_disk
import numpy as np
import pandas as pd
from scipy.optimize import curve_fit
d = load_from_disk('/app/data')
df = pd.DataFrame({'V': d['vocab_size'], 'N': d['non_vocab_parameters'], 'C': d['num_characters'], 'L': d['unigram_normalized_loss']})
V = df.V.values; N = df.N.values; C = df.C.values; L = df.L.values

# Tao et al style: L_u = -E*V^gamma + A/Nnv^alpha + B/D^beta  where D = num_characters
def m3(X, E, gamma, A, alpha, B, beta):
    N,C,V = X
    return -E*V**gamma + A*N**(-alpha) + B*C**(-beta)

p0 = [1.0, 0.1, 50, 0.3, 5000, 0.4]
try:
    popt,_ = curve_fit(m3, (N,C,V), L, p0=p0, maxfev=100000)
    pred = m3((N,C,V),*popt)
    print('m3:', popt, 'RMSE:', np.sqrt(np.mean((pred-L)**2)))
except Exception as e: print('m3 fail', e)

# Add a V-dep on parameter cost: total params = N + V*d_embed; d_embed might scale w/ N
# Or simpler: total N_total = N * (1 + c*V^p)
def m4(X, E, A, alpha, B, beta, c, p):
    N,C,V = X
    Ntot = N + c*V**p
    return E + A*Ntot**(-alpha) + B*C**(-beta)

p0 = [-5.5, 30, 0.25, 5000, 0.4, 1.0, 1.0]
try:
    popt,_ = curve_fit(m4, (N,C,V), L, p0=p0, maxfev=100000)
    pred = m4((N,C,V),*popt)
    print('m4:', popt, 'RMSE:', np.sqrt(np.mean((pred-L)**2)))
except Exception as e: print('m4 fail', e)

# Try fully separable with V power
def m5(X, E, A, alpha, B, beta, gV, gV2):
    N,C,V = X
    return E - gV*V**gV2 + A*N**(-alpha) + B*C**(-beta)

p0=[-5.5, 30,0.25,5000,0.4,0.01,0.5]
try:
    popt,_ = curve_fit(m5,(N,C,V),L,p0=p0,maxfev=100000)
    pred=m5((N,C,V),*popt)
    print('m5:', popt, 'RMSE:', np.sqrt(np.mean((pred-L)**2)))
except Exception as e: print('m5 fail', e)

# Tao et al actually has: L = -E*V^gamma + A/N_nv^alpha + B/(V*D)^beta
# Because data D = chars, but effective number of tokens depends on tokenizer (V)
def m6(X, E, gamma, A, alpha, B, beta):
    N,C,V = X
    return -E*V**gamma + A*N**(-alpha) + B*(C*V)**(-beta)

p0=[1.0, 0.1, 30, 0.3, 5000, 0.4]
try:
    popt,_ = curve_fit(m6,(N,C,V),L,p0=p0,maxfev=100000)
    pred=m6((N,C,V),*popt)
    print('m6:', popt, 'RMSE:', np.sqrt(np.mean((pred-L)**2)))
except Exception as e: print('m6 fail', e)
